  ('medical-tech-moex-01598', 'medical-tech', 'medical-tech-moex-114-483fb9c7', 'sub-medical-tech-01', NULL, 'single_choice', '某  病人之血清脂蛋白電泳圖，顯示β帶明顯增加，可是血清外觀並無異樣，則下列敘述何者正確？', '["該  病人之HDL大量增加", "可  能是該病人之LPL基因突變所導致", "屬  於第三型高血脂症（type III hyperlipoproteinemia）", "顯  示該病人血清中的膽固醇已過量"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:04+00:00", "source_pdf_sha1": "e03c03703695", "answer_pdf_sha1": "10689f89b7d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114020", "c": "308", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生物化學與臨床生化學", "year": "114", "exam_name": "114年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
